//
//  NewOpenAIClient.swift
//  FitToday
//
//  Created by AI on 09/02/26.
//  Part of: Workout Experience Overhaul (Task 3.0)
//

import Foundation

/// Simplified OpenAI client focused on workout generation.
///
/// Key features:
/// - Single responsibility: generate workouts via OpenAI API
/// - Built-in retry logic (up to 2 retries on network errors)
/// - No caching (handled at composer level if needed)
/// - Clean error handling
///
/// - Note: Part of FR-002 (OpenAI Generation Enhancement) from PRD
actor NewOpenAIClient: Sendable {

    // MARK: - Types

    enum ClientError: Error, LocalizedError {
        case missingAPIKey
        case invalidResponse
        case httpError(statusCode: Int, message: String)
        case decodingError(String)
        case emptyWorkoutResponse

        var errorDescription: String? {
            switch self {
            case .missingAPIKey:
                return "OpenAI API key not configured"
            case .invalidResponse:
                return "Invalid response from OpenAI"
            case .httpError(let code, let message):
                return "HTTP \(code): \(message)"
            case .decodingError(let detail):
                return "Failed to decode response: \(detail)"
            case .emptyWorkoutResponse:
                return "OpenAI returned an empty workout response"
            }
        }
    }

    // MARK: - Configuration

    private let apiKey: String
    private let model: String
    private let baseURL: URL
    private let timeout: TimeInterval
    private let maxTokens: Int
    private let temperature: Double
    private let maxRetries: Int

    private let session: URLSession

    // MARK: - Initialization

    init(
        apiKey: String,
        model: String = "gpt-4o-mini",
        baseURL: URL = URL(string: "https://api.openai.com/v1/chat/completions")!,
        timeout: TimeInterval = 60,
        maxTokens: Int = 2000,
        temperature: Double = 0.55,
        maxRetries: Int = 2
    ) {
        self.apiKey = apiKey
        self.model = model
        self.baseURL = baseURL
        self.timeout = timeout
        self.maxTokens = maxTokens
        self.temperature = temperature
        self.maxRetries = maxRetries

        let sessionConfig = URLSessionConfiguration.ephemeral
        sessionConfig.timeoutIntervalForRequest = timeout
        self.session = URLSession(configuration: sessionConfig)
    }

    /// Factory method to create client from user's stored API key
    static func fromUserKey() -> NewOpenAIClient? {
        guard let apiKey = UserAPIKeyManager.shared.getAPIKey(for: .openAI),
              !apiKey.isEmpty else {
            return nil
        }

        return NewOpenAIClient(apiKey: apiKey)
    }

    // MARK: - Public API

    /// Generates a workout by sending a prompt to OpenAI.
    ///
    /// - Parameter prompt: The complete prompt (system + user messages combined)
    /// - Returns: Raw JSON data containing the workout response
    /// - Throws: ClientError if the request fails after retries
    func generateWorkout(prompt: String) async throws -> Data {
        var lastError: Error?

        // Retry loop
        for attempt in 0...maxRetries {
            do {
                let data = try await performRequest(prompt: prompt)

                #if DEBUG
                if attempt > 0 {
                    print("[NewOpenAIClient] ✅ Request succeeded on attempt \(attempt + 1)")
                }
                #endif

                return data
            } catch {
                lastError = error

                #if DEBUG
                print("[NewOpenAIClient] ⚠️ Attempt \(attempt + 1) failed: \(error.localizedDescription)")
                #endif

                // Don't retry on client errors (4xx)
                if case ClientError.httpError(let code, _) = error, (400..<500).contains(code) {
                    throw error
                }

                // Small delay before retry
                if attempt < maxRetries {
                    try? await Task.sleep(nanoseconds: 500_000_000) // 0.5 seconds
                }
            }
        }

        // All retries exhausted
        throw lastError ?? ClientError.invalidResponse
    }

    /// Sends a chat completion request with conversation history.
    ///
    /// - Parameters:
    ///   - messages: Array of message dictionaries with "role" and "content" keys
    ///   - maxTokens: Maximum tokens in response (default 1000)
    ///   - temperature: Randomness (default 0.7)
    /// - Returns: The assistant's response content string
    func sendChat(
        messages: [[String: String]],
        maxTokens: Int = 1000,
        temperature: Double = 0.7
    ) async throws -> String {
        var lastError: Error?

        for attempt in 0...maxRetries {
            do {
                let content = try await performChatRequest(
                    messages: messages,
                    maxTokens: maxTokens,
                    temperature: temperature
                )
                return content
            } catch {
                lastError = error

                #if DEBUG
                print("[NewOpenAIClient] ⚠️ Chat attempt \(attempt + 1) failed: \(error.localizedDescription)")
                #endif

                if case ClientError.httpError(let code, _) = error, (400..<500).contains(code) {
                    throw error
                }

                if attempt < maxRetries {
                    try? await Task.sleep(nanoseconds: 500_000_000)
                }
            }
        }

        throw lastError ?? ClientError.invalidResponse
    }

    // MARK: - Private Helpers

    private func performRequest(prompt: String) async throws -> Data {
        // 1. Build request
        var request = URLRequest(url: baseURL)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")

        // 2. Build payload
        let messages: [[String: String]] = [
            [
                "role": "system",
                "content": "You are an expert personal trainer who creates personalized workout plans. Always respond with valid JSON following the requested schema."
            ],
            [
                "role": "user",
                "content": prompt
            ]
        ]

        let payload: [String: Any] = [
            "model": model,
            "messages": messages,
            "max_tokens": maxTokens,
            "temperature": temperature,
            "response_format": ["type": "json_object"]
        ]

        request.httpBody = try JSONSerialization.data(withJSONObject: payload)

        // 3. Perform request
        let (data, response) = try await session.data(for: request)

        // 4. Validate response
        guard let httpResponse = response as? HTTPURLResponse else {
            throw ClientError.invalidResponse
        }

        guard (200..<300).contains(httpResponse.statusCode) else {
            let message = String(data: data, encoding: .utf8) ?? "No details"
            throw ClientError.httpError(statusCode: httpResponse.statusCode, message: message)
        }

        return data
    }

    private func performChatRequest(
        messages: [[String: String]],
        maxTokens: Int,
        temperature: Double
    ) async throws -> String {
        var request = URLRequest(url: baseURL)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")

        let payload: [String: Any] = [
            "model": model,
            "messages": messages,
            "max_tokens": maxTokens,
            "temperature": temperature
        ]

        request.httpBody = try JSONSerialization.data(withJSONObject: payload)

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw ClientError.invalidResponse
        }

        guard (200..<300).contains(httpResponse.statusCode) else {
            let message = String(data: data, encoding: .utf8) ?? "No details"
            throw ClientError.httpError(statusCode: httpResponse.statusCode, message: message)
        }

        let decoded = try JSONDecoder().decode(ChatCompletionResponse.self, from: data)

        guard let content = decoded.choices.first?.message.content, !content.isEmpty else {
            throw ClientError.emptyWorkoutResponse
        }

        return content
    }
}

/// Response model for OpenAI Chat Completions API
struct ChatCompletionResponse: Decodable, Sendable {
    let choices: [Choice]

    struct Choice: Decodable, Sendable {
        let message: Message
    }

    struct Message: Decodable, Sendable {
        let content: String?
    }
}

// Workout Composition - New simplified OpenAI stack
// Enhanced local composer with variation validation
let historyRepo = container.resolve(WorkoutHistoryRepository.self)!
let enhancedLocalComposer = EnhancedLocalWorkoutPlanComposer(
    historyRepository: historyRepo
)
container.register(EnhancedLocalWorkoutPlanComposer.self) { _ in enhancedLocalComposer }
    .inObjectScope(.container)

// WorkoutPlanComposing: Use OpenAI if available, otherwise enhanced local
container.register(WorkoutPlanComposing.self) { resolver in
    let historyRepository = resolver.resolve(WorkoutHistoryRepository.self)!

    // Try to create OpenAI composer if API key is configured
    if let client = NewOpenAIClient.fromUserKey() {
        return NewOpenAIWorkoutComposer(
            client: client,
            localFallback: enhancedLocalComposer,
            historyRepository: historyRepository
        )
    } else {
        // No API key - use enhanced local composer
        return enhancedLocalComposer
    }
}
.inObjectScope(.container)

// HealthKit (iPhone) - serviço de integração (PRO gating é feito na UI/fluxos)
let healthKitService = HealthKitService()
container.register(HealthKitServicing.self) { _ in healthKitService }
    .inObjectScope(.container)

// Note: HealthKitHistorySyncService is registered later after SyncWorkoutCompletionUseCase is available

// HealthKit Workout Sync Use Case - auto-exports workouts and imports calories
container.register(SyncWorkoutWithHealthKitUseCase.self) { resolver in
    SyncWorkoutWithHealthKitUseCase(
        healthKitService: resolver.resolve(HealthKitServicing.self)!,
        historyRepository: resolver.resolve(WorkoutHistoryRepository.self)!

