//
//  ExerciseAnimatedView.swift
//  FitToday
//
//  Created by Claude on 03/03/26.
//

import Combine
import SwiftUI
import UIKit

/// Alternates between image 0 and image 1 every 1.2s to simulate a GIF.
/// Falls back to a static image if only image 0 exists.
/// Timer stops when the view disappears to prevent memory leaks.
struct ExerciseAnimatedView: View {
    let exerciseId: String
    var cornerRadius: CGFloat = 12

    @State private var image0: UIImage?
    @State private var image1: UIImage?
    @State private var showingIndex0 = true
    @State private var isLoaded = false

    private let timer = Timer.publish(every: 1.2, on: .main, in: .common)
    @State private var timerCancellable: Cancellable?

    var body: some View {
        Group {
            if !isLoaded {
                ZStack {
                    RoundedRectangle(cornerRadius: cornerRadius)
                        .fill(FitTodayColor.surface)
                    ProgressView()
                        .tint(FitTodayColor.brandSecondary)
                }
            } else if let currentImage {
                Image(uiImage: currentImage)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .animation(.easeInOut(duration: 0.3), value: showingIndex0)
            } else {
                ZStack {
                    RoundedRectangle(cornerRadius: cornerRadius)
                        .fill(FitTodayColor.surface)
                    Image(systemName: "figure.strengthtraining.traditional")
                        .font(.system(size: 40))
                        .foregroundStyle(FitTodayColor.textTertiary)
                }
            }
        }
        .clipShape(RoundedRectangle(cornerRadius: cornerRadius))
        .task(id: exerciseId) {
            await loadImages()
        }
        .onAppear { startTimer() }
        .onDisappear { stopTimer() }
    }

    private var currentImage: UIImage? {
        if showingIndex0 {
            return image0
        }
        return image1 ?? image0
    }

    private func loadImages() async {
        image0 = await ExerciseImageCache.shared.image(for: exerciseId, imageIndex: 0)
        image1 = await ExerciseImageCache.shared.image(for: exerciseId, imageIndex: 1)
        isLoaded = true
        if image1 != nil {
            startTimer()
        }
    }

    private func startTimer() {
        guard timerCancellable == nil else { return }
        timerCancellable = timer.autoconnect().sink { _ in
            showingIndex0.toggle()
        }
    }

    private func stopTimer() {
        timerCancellable?.cancel()
        timerCancellable = nil
    }
}

//
//  ButtonStyles.swift
//  FitToday
//
//  Design System - Button Styles
//  Dark Theme (Gym App UI Kit Style)
//

import SwiftUI

struct FitPrimaryButtonStyle: ButtonStyle {
    @Environment(\.isEnabled) private var isEnabled
    @ScaledMetric private var verticalPadding: CGFloat = 16

    func makeBody(configuration: Configuration) -> some View {
        configuration.label
            .font(FitTodayFont.ui(size: 17, weight: .bold))            .textCase(.uppercase)            .tracking(1.0)  // Letter spacing
            .frame(maxWidth: .infinity)
            .padding(.vertical, verticalPadding)
            .background(backgroundColor(configuration: configuration))
            .foregroundStyle(FitTodayColor.textInverse)
            .clipShape(Capsule())
            .overlay(
                Group {
                    if configuration.isPressed {
                        Capsule()
                            .fill(Color.white.opacity(0.1))
                    }
                }
            )
            .opacity(isEnabled ? 1 : 0.4)
            .scaleEffect(configuration.isPressed ? 0.97 : 1)
            .animation(.spring(response: 0.3, dampingFraction: 0.7), value: configuration.isPressed)
            .contentShape(Capsule())
            .fitGlowEffect(color: FitTodayColor.brandPrimary.opacity(isEnabled && !configuration.isPressed ? 0.3 : 0))
    }

    private func backgroundColor(configuration: Configuration) -> Color {
        configuration.isPressed ? FitTodayColor.brandPrimary.opacity(0.85) : FitTodayColor.brandPrimary
    }
}

struct FitSecondaryButtonStyle: ButtonStyle {
    @Environment(\.isEnabled) private var isEnabled
    @ScaledMetric private var verticalPadding: CGFloat = 14

    func makeBody(configuration: Configuration) -> some View {
        configuration.label
            .font(FitTodayFont.ui(size: 17, weight: .semiBold))            .textCase(.uppercase)            .tracking(1.0)  // Letter spacing
            .frame(maxWidth: .infinity)
            .padding(.vertical, verticalPadding)
            .background(
                Capsule()
                    .fill(FitTodayColor.surface)
                    .overlay(
                        Capsule()
                            .stroke(FitTodayColor.brandPrimary, lineWidth: 1.5)
                    )
            )
            .overlay(
                Group {
                    if configuration.isPressed {
                        Capsule()
                            .fill(FitTodayColor.brandPrimary.opacity(0.1))
                    }
                }
            )
            .foregroundStyle(FitTodayColor.brandPrimary)
            .opacity(isEnabled ? (configuration.isPressed ? 0.7 : 1) : 0.4)
            .scaleEffect(configuration.isPressed ? 0.98 : 1)
            .animation(.spring(response: 0.3, dampingFraction: 0.7), value: configuration.isPressed)
            .contentShape(Capsule())
            .fitGlowEffect(color: FitTodayColor.brandPrimary.opacity(isEnabled && !configuration.isPressed ? 0.2 : 0))
    }
}

struct FitDestructiveButtonStyle: ButtonStyle {
    @Environment(\.isEnabled) private var isEnabled
    @ScaledMetric private var verticalPadding: CGFloat = 14

    func makeBody(configuration: Configuration) -> some View {
        configuration.label
            .font(FitTodayFont.ui(size: 17, weight: .semiBold))            .textCase(.uppercase)            .tracking(1.0)  // Letter spacing
            .frame(maxWidth: .infinity)
            .padding(.vertical, verticalPadding)
            .background(
                Capsule()
                    .fill(configuration.isPressed ? FitTodayColor.error.opacity(0.8) : FitTodayColor.error)
            )
            .overlay(
                Group {
                    if configuration.isPressed {
                        Capsule()
                            .fill(FitTodayColor.error.opacity(0.2))
                    }
                }
            )
            .foregroundStyle(Color.white)
            .opacity(isEnabled ? 1 : 0.4)
            .scaleEffect(configuration.isPressed ? 0.98 : 1)
            .animation(.spring(response: 0.3, dampingFraction: 0.7), value: configuration.isPressed)
            .contentShape(Capsule())
            .fitGlowEffect(color: FitTodayColor.error.opacity(isEnabled && !configuration.isPressed ? 0.2 : 0))  // Error glow
    }
}

extension Button {
    func fitPrimaryStyle() -> some View {
        buttonStyle(FitPrimaryButtonStyle())
            .buttonBorderShape(.capsule)
    }

    func fitSecondaryStyle() -> some View {
        buttonStyle(FitSecondaryButtonStyle())
            .buttonBorderShape(.capsule)
    }

    func fitDestructiveStyle() -> some View {
        buttonStyle(FitDestructiveButtonStyle())
            .buttonBorderShape(.capsule)
    }
}

