315→    private func exportToHealthKitIfPossible() async {
316→        guard status == .completed else { return }
317→        guard canUseHealthKit, healthKitState == .authorized else {
318→            healthKitExportMessage = "Conecte o Apple Health antes de exportar."
319→            return
320→        }
321→        guard let plan = sessionStore.plan else { return }
322→        guard
323→            let healthKit = resolver.resolve(HealthKitServicing.self),
324→            let historyRepo = resolver.resolve(WorkoutHistoryRepository.self)
325→        else { return }
326→        
327→        do {
328→            isExportingHealthKit = true
329→            defer { isExportingHealthKit = false }
330→            
331→            let receipt = try await healthKit.exportWorkout(plan: plan, completedAt: Date())
332→            
333→            // Vincular UUID ao último item do histórico com este planId (melhor esforço)
334→            let recent = try await historyRepo.listEntries(limit: 20, offset: 0)
335→            if let idx = recent.firstIndex(where: { $0.planId == plan.id }) {
336→                var updated = recent[idx]
337→                updated.healthKitWorkoutUUID = receipt.workoutUUID
338→                try await historyRepo.saveEntry(updated)
339→            }
340→            
