347→    private func generateNewWorkout() {
348→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
349→              let blocksRepo = resolver.resolve(WorkoutBlocksRepository.self),
350→              let composer = resolver.resolve(WorkoutPlanComposing.self) else {
351→            errorMessage = "Não foi possível carregar as configurações necessárias."
352→            return
353→        }
354→        
355→        isGeneratingNewPlan = true
356→        
357→        Task {
358→            do {
359→                // Busca o último checkIn usado (pode ser armazenado em UserDefaults ou no sessionStore)
360→                // Por enquanto, vamos usar o checkIn padrão baseado no perfil
361→                let profileUseCase = GetUserProfileUseCase(repository: profileRepo)
362→                guard let profile = try await profileUseCase.execute() else {
363→                    errorMessage = "Perfil não encontrado. Configure seu perfil primeiro."
364→                    isGeneratingNewPlan = false
365→                    return
366→                }
367→                
368→                // Gera um novo checkIn baseado no último foco usado (ou padrão)
369→                // Para simplificar, vamos usar o mesmo foco do plano atual
370→                let currentFocus = sessionStore.plan?.focus ?? .fullBody
371→                let checkIn = DailyCheckIn(
372→                    focus: currentFocus,
373→                    sorenessLevel: .none, // Novo treino sem considerar dor anterior
374→                    sorenessAreas: [],
375→                    energyLevel: 5
376→                )
377→                
378→                let generator = GenerateWorkoutPlanUseCase(
379→                    blocksRepository: blocksRepo,
380→                    composer: composer
381→                )
382→                let newPlan = try await generator.execute(profile: profile, checkIn: checkIn)
383→                
384→                await MainActor.run {
385→                    sessionStore.reset()
386→                    sessionStore.start(with: newPlan)
387→                    isGeneratingNewPlan = false
388→                    
389→                    // Navega para o novo treino
390→                    router.pop(on: .home) // summary
391→                    router.push(.workoutPlan(newPlan.id), on: .home)
392→                }
393→            } catch {
394→                await MainActor.run {
395→                    errorMessage = error.localizedDescription
396→                    isGeneratingNewPlan = false
397→                }
398→            }
399→        }
400→    }
