402→    private func finalizeFlow(goToHistory: Bool) {
403→        sessionStore.reset()
404→        router.pop(on: .home) // summary
405→        router.pop(on: .home) // detail
406→        router.pop(on: .home) // workout list
407→
408→        if goToHistory {
