            HStack(spacing: FitTodaySpacing.sm) {
                Image(systemName: "clock.fill")
                    .foregroundStyle(FitTodayColor.brandPrimary)
                    .font(.title3)

                VStack(alignment: .leading, spacing: 2) {
                    Text("Tempo Total")
                        .font(.footnote)
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Text(sessionStore.formattedLastWorkoutTime)
                        .font(.title3.weight(.semibold))
                        .foregroundStyle(FitTodayColor.textPrimary)
                }

                Spacer()
            }

            Divider()

            // Exercises completed
            HStack(spacing: FitTodaySpacing.sm) {
                Image(systemName: "checkmark.circle.fill")
                    .foregroundStyle(FitTodayColor.brandPrimary)
                    .font(.title3)

                VStack(alignment: .leading, spacing: 2) {
                    Text("Exercícios")
                        .font(.footnote)
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Text("\(sessionStore.completedExercisesCount) de \(sessionStore.exerciseCount)")
                        .font(.title3.weight(.semibold))
                        .foregroundStyle(FitTodayColor.textPrimary)
                }

                Spacer()
            }
        }
        .padding()
        .background(
            RoundedRectangle(cornerRadius: FitTodayRadius.md)
                .fill(FitTodayColor.brandPrimary.opacity(0.08))
                .overlay(
                    RoundedRectangle(cornerRadius: FitTodayRadius.md)
                        .stroke(FitTodayColor.brandPrimary.opacity(0.2), lineWidth: 1)
                )
        )
        .padding(.horizontal)
    }

    // MARK: - Success Feedback

    private func playSuccessHapticIfNeeded() {
        guard status == .completed, !didPlayHaptic else { return }
        didPlayHaptic = true

        // Play success haptic feedback
        let generator = UINotificationFeedbackGenerator()
        generator.notificationOccurred(.success)
    }

    // MARK: - App Store Review

    private func requestAppReviewIfEligible() {
        guard status == .completed else { return }

        Task {
            let service = AppReviewService()
            let workoutCount = await fetchWorkoutCount()

            guard service.isEligible(completedWorkoutsCount: workoutCount) else { return }

            // Delay per Apple guidelines — let user absorb the moment
            try? await Task.sleep(for: .seconds(2))

            service.recordReviewRequest()
            await requestReview()
        }
    }

    private func fetchWorkoutCount() async -> Int {
        guard let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) else {
            return 0
        }
        return (try? await historyRepo.count()) ?? 0
    }
}

