      XCTAssertFalse(fullText.contains("URLError"))
      XCTAssertFalse(fullText.contains("HTTP"))
      XCTAssertFalse(fullText.contains("nil"))
      XCTAssertFalse(fullText.contains("null"))
    }
  }
}

